   121→func checkPutRequest(r *pb.PutRequest) error {
   122→	if len(r.Key) == 0 {
   123→		return rpctypes.ErrGRPCEmptyKey
   124→	}
   125→	if r.IgnoreValue && len(r.Value) != 0 {
   126→		return rpctypes.ErrGRPCValueProvided
   127→	}
   128→	if r.IgnoreLease && r.Lease != 0 {
